def merge_intervals(intervals):
    '''Merge overlapping intervals'''
    merged = []
    for i in sorted(intervals):
        if not merged or merged[-1][1] < i[0]:
            merged.append(i) # no overlap, append original interval
        else:
            merged[-1] = (merged[-1][0], max(merged[-1][1], i[1])) # there is an overlap, merge intervals 
    return merged```
